from typing import List

class Solution:
    def addOperators(self, num: str, target: int) -> List[str]:
        def backtrack(index: int, path: str, value: int, prev: int) -> None:
            if index == len(num):
                if value == target:
                    result.append(path)
                return
            for i in range(index, len(num)):
                if i != index and num[index] == '0':
                    break
                str_num = num[index:i+1]
                curr = int(str_num)
                if index == 0:
                    backtrack(i + 1, path + str_num, curr, curr)
                else:
                    backtrack(i + 1, path + '+' + str_num, value + curr, curr)
                    backtrack(i + 1, path + '-' + str_num, value - curr, -curr)
                    backtrack(i + 1, path + '*' + str_num, value - prev + prev * curr, prev * curr)

