using namespace std;

class Solution {
public:
    vector<string> addOperators(string num, int target) {
        vector<string> result;
        backtrack(result, num, target, 0, "", 0, 0);
        return result;
    }

    void backtrack(vector<string>& result, string num, int target, int index, string path, long value, long prev) {
        if (index == num.size()) {
            if (value == target) {
                result.push_back(path);
            }
            return;
        }
        for (int i = index; i < num.size(); i++) {
            if (i != index && num[index] == '0') {
                break;
            }
            string str_num = num.substr(index, i - index + 1);
            long curr = stol(str_num);
            if (index == 0) {
                backtrack(result, num, target, i + 1, path + str_num, curr, curr);
            } else {
                backtrack(result, num, target, i + 1, path + '+' + str_num, value + curr, curr);
                backtrack(result, num, target, i + 1, path + '-' + str_num, value - curr, -curr);
                backtrack(result, num, target, i + 1, path + '*' + str_num, value - prev + prev * curr, prev * curr);
            }
        }
    }
};

